var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"SECRETARY_FRONTBAY_NULL_ADMIN","text":{"KOREA":"크라켄의 후퇴 이후, 검은 범람은 종식.","JPN":"クラーケンの後退以後、黒い氾濫は終息。","ENG":"After Kraken's retreat, the Black Flood had ended.","TWN":"克拉肯撤退後，黑色洪災也就結束了。"},"stage":{"bg":"PROLOGUE_02","slots":{"L":null,"C":{"char_id":"SECRETARY_FRONTBAY_NULL_ADMIN","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"SECRETARY_FRONTBAY_NULL_ADMIN","text":{"KOREA":"심해역의 이상 활동이 멎으면서 침식레벨도 급격히 안정화단계에 접어들었습니다.","JPN":"深海域の異常活動が止まり、侵食レベルも急激に安定化の段階に入りました。","ENG":"Abnormal activities in the deep sea area have stopped, and Corruption levels have rapidly entered the stabilization phase.","TWN":"隨著深海域異常活動的停止，侵蝕等級也迅速趨於穩定。"},"stage":{"bg":"PROLOGUE_02","slots":{"L":null,"C":{"char_id":"SECRETARY_FRONTBAY_NULL_ADMIN","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"JACK_FRONTBAY_NULL_NULL","text":{"KOREA":"하지만 사라지지 않았군. 당연하게도 말이지.","JPN":"だが、消えてはいなかったな。当然のことではあるが。","ENG":"But it didn't go away. Of course.","TWN":"但，危險還沒有消失。"},"stage":{"bg":"PROLOGUE_02","slots":{"L":null,"C":{"char_id":"JACK_FRONTBAY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"SECRETARY_FRONTBAY_NULL_ADMIN","text":{"KOREA":"크라켄의 완전토벌은 이론상 불가능한 얘기죠.","JPN":"クラーケンの完全討伐は理論上、不可能な話です。","ENG":"Theoretically, the complete annihilation of Kraken is impossible.","TWN":"從理論上講，完全擊敗克拉肯是不可能的。"},"stage":{"bg":"PROLOGUE_02","slots":{"L":null,"C":{"char_id":"SECRETARY_FRONTBAY_NULL_ADMIN","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"SECRETARY_FRONTBAY_NULL_ADMIN","text":{"KOREA":"세포조직 하나만 살아있어도 무한히 재생하는 괴물체가 대양의 수조 밑바닥을 가득 채우고 있으니까요.","JPN":"細胞組織が一つだけ生きていても無限に再生する怪物体が、大海の水槽の底を埋め尽くしていますから。","ENG":"A monster that can regenerate itself with just one tissue cell is taking up all the space on the ocean floor.","TWN":"海洋這個大型水箱的底部充滿了畸形的、無限再生的生物。"},"stage":{"bg":"PROLOGUE_02","slots":{"L":null,"C":{"char_id":"SECRETARY_FRONTBAY_NULL_ADMIN","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"SECRETARY_FRONTBAY_NULL_ADMIN","text":{"KOREA":"하지만 그래도…","JPN":"ですが、それでも……","ENG":"But still...","TWN":"但就算如此……"},"stage":{"bg":"PROLOGUE_02","slots":{"L":null,"C":{"char_id":"SECRETARY_FRONTBAY_NULL_ADMIN","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"SECRETARY_FRONTBAY_NULL_ADMIN","text":{"KOREA":"앞으로 수년간은 잠잠할 겁니다.","JPN":"これから数年は静かでしょう。","ENG":"The seas will be calm for several years or so.","TWN":"在未來的幾年裡，我們獲得了短暫的和平。"},"stage":{"bg":"PROLOGUE_02","slots":{"L":null,"C":{"char_id":"SECRETARY_FRONTBAY_NULL_ADMIN","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"SECRETARY_FRONTBAY_NULL_ADMIN","text":{"KOREA":"문제는 그 수년 뒤가 되겠죠.","JPN":"問題はその数年後です。","ENG":"The problem is after those peaceful years.","TWN":"問題將會在之後再次來臨。"},"stage":{"bg":"PROLOGUE_02","slots":{"L":null,"C":{"char_id":"SECRETARY_FRONTBAY_NULL_ADMIN","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"JACK_FRONTBAY_NULL_NULL","text":{"KOREA":"모두에게 보여주지 않았나?","JPN":"みんなに見せたはずだ。","ENG":"Didn't we prove it to everyone?","TWN":"大家都看到了不是嗎？"},"stage":{"bg":"PROLOGUE_02","slots":{"L":null,"C":{"char_id":"JACK_FRONTBAY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"JACK_FRONTBAY_NULL_NULL","text":{"KOREA":"아무리 끔찍하고 거대한 존재라도… 결국 쓰러트릴 수 있단 사실을 말이야.","JPN":"どんなに恐ろしく巨大な存在であっても……結局は倒せるという事実を。","ENG":"That no matter how horrific of a monster... that it can still be defeated.","TWN":"無論是多麼可怕、多麼巨大的敵人……我們都能達到他們。"},"stage":{"bg":"PROLOGUE_02","slots":{"L":null,"C":{"char_id":"JACK_FRONTBAY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"SECRETARY_FRONTBAY_NULL_ADMIN","text":{"KOREA":"네, 시니어님께선… 정말 목숨까지 걸어가며 프론트베이의 사람들에게 그 사실을 증명하셨죠.","JPN":"はい、シニア様は……本当に命をかけてまでフロントベイの人々にその事実を証明しました。","ENG":"Yes. Because you risked your life... to prove it to everyone in Front Bay, Senior.","TWN":"是的，Senior……你冒著生命危險向前灣的人民證明了這一點。"},"stage":{"bg":"PROLOGUE_02","slots":{"L":null,"C":{"char_id":"SECRETARY_FRONTBAY_NULL_ADMIN","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"SECRETARY_FRONTBAY_NULL_ADMIN","text":{"KOREA":"하지만 이 보고서는 정말 터무니없네요.","JPN":"ですが、この報告書はまったくとんでもありません。","ENG":"But this report is just ridiculous.","TWN":"但這份報告絕對是不可行的。"},"stage":{"bg":"PROLOGUE_02","slots":{"L":null,"C":{"char_id":"SECRETARY_FRONTBAY_NULL_ADMIN","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"SECRETARY_FRONTBAY_NULL_ADMIN","text":{"KOREA":"이번엔 보물이라는 미끼와 변수에 변수가 맞물리면서 성공할 수 있었지만…","JPN":"今回は宝というオトリと変数に変数が重なって成功できましたが……","ENG":"Although it was able to succeed using the treasure as bait among other variables working together...","TWN":"這一次，有了寶藏的誘餌和變數的作用，有幸成功了……"},"stage":{"bg":"PROLOGUE_02","slots":{"L":null,"C":{"char_id":"SECRETARY_FRONTBAY_NULL_ADMIN","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"SECRETARY_FRONTBAY_NULL_ADMIN","text":{"KOREA":"다음번에도 헌터들이 심해역의 소용돌이까지 목숨을 걸고 가리란 보장은 할 수 없습니다.","JPN":"次回もハンターが深海域の渦まで命をかけて行くという保証はできません。","ENG":"I cannot guarantee that the hunters will be willing to risk their lives again by entering the vortex in the deep sea area.","TWN":"但誰也不能保證，下一次獵人們還會不會冒著生命危險，抵禦深海漩渦。"},"stage":{"bg":"PROLOGUE_02","slots":{"L":null,"C":{"char_id":"SECRETARY_FRONTBAY_NULL_ADMIN","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"SECRETARY_FRONTBAY_NULL_ADMIN","text":{"KOREA":"게다가, 현역으로 뛰기엔 많이 나이가 드셨어요. 그때가 되면 무기를 손에 쥐는 것도 버거울 겁니다.","JPN":"それに、現役で走り回るにはもうお年です。いざという時、武器を手にするのも大変でしょう。","ENG":"On top of that, you are too old to be out on the field. When the time comes, it will be hard for you to wield a weapon.","TWN":"而且，你作為現役，年紀已經不小了，到那時，你還能拿得動手中的武器嗎。"},"stage":{"bg":"PROLOGUE_02","slots":{"L":null,"C":{"char_id":"JACK_FRONTBAY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"JACK_FRONTBAY_NULL_NULL","text":{"KOREA":"핫핫핫! 인공지능 비서가 이렇게까지 정곡을 찌르는 험담을 늘어놓다니. 참 무서운 시대구만.","JPN":"ハハハ！　人工知能秘書がここまで耳が痛い悪口を並べるとは。恐ろしい時代だ。","ENG":"Hahaha! I can't believe I'm getting pummeled with facts by an AI Secretary. What a scary age we live in.","TWN":"哈哈哈！這個時代真可怕，連人工智慧秘書都知道一本正經的挖苦人了。"},"stage":{"bg":"PROLOGUE_02","slots":{"L":null,"C":{"char_id":"JACK_FRONTBAY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"JACK_FRONTBAY_NULL_NULL","text":{"KOREA":"하지만 걱정말라고. 그때가 되면 해역을 지키는 건 내가 아닐 테니까.","JPN":"だが、心配するな。その時になれば、海域を守るのは私ではないはずだからな。","ENG":"But don't you worry. Because when the time comes, I won't be the one protecting the sea.","TWN":"不過別擔心，到時候守護海域的人不會是我。"},"stage":{"bg":"PROLOGUE_02","slots":{"L":null,"C":{"char_id":"JACK_FRONTBAY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"SECRETARY_FRONTBAY_NULL_ADMIN","text":{"KOREA":"네?","JPN":"はい？","ENG":"Excuse me?","TWN":"什麼？"},"stage":{"bg":"PROLOGUE_02","slots":{"L":null,"C":{"char_id":"SECRETARY_FRONTBAY_NULL_ADMIN","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"JACK_FRONTBAY_NULL_NULL","text":{"KOREA":"자네 말대로 대해적 에이버리의 시대는 진작에 끝났어.","JPN":"君の言うとおり、大海賊エイバリーの時代はとっくに終わっている。","ENG":"Like you said, the Great Pirate Avery's time has ended a long time ago.","TWN":"你說得對，大海大艾維利的時代早就結束了。"},"stage":{"bg":"PROLOGUE_02","slots":{"L":null,"C":{"char_id":"JACK_FRONTBAY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"JACK_FRONTBAY_NULL_NULL","text":{"KOREA":"다음 골칫거리는 다음 세대에게 맡겨야지.","JPN":"次の問題は次の世代に任せないと。","ENG":"It'll be up to the next generation to deal with future troubles.","TWN":"之後令人頭疼的問題留給下一代吧。"},"stage":{"bg":"PROLOGUE_02","slots":{"L":null,"C":{"char_id":"JACK_FRONTBAY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"JACK_FRONTBAY_NULL_NULL","text":{"KOREA":"……최고 관리자님이 원하셨던 것처럼.","JPN":"……最高管理者が望んでいたように。","ENG":"...Just like the Supreme Administrator wanted it.","TWN":"……就像最高管理者所期望的那樣。"},"stage":{"bg":"PROLOGUE_02","slots":{"L":null,"C":{"char_id":"JACK_FRONTBAY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"JACK_FRONTBAY_NULL_NULL","text":{"KOREA":"함선의 잔해 회수는 어떻게 됐지?","JPN":"艦船の残骸回収はどうなっている？","ENG":"What happened to the retrieval of the ship's debris?","TWN":"艦船殘骸打撈工作進展如何了？"},"stage":{"bg":"HANGAR","slots":{"L":null,"C":null,"R":{"char_id":"JACK_FRONTBAY_NULL_NULL","face":"UNIT_IDLE"}}}}]`);export{e as default};